const express = require('express');
const fs = require('fs');
const { parseString, resolveEntity } = require('xml2js');

const app = express();

app.post('/xml-parser', (req, res) => {
  const xml = req.body.xml;

  resolveEntity(xml, (resolvedXml) => {
    parseString(resolvedXml, { explicitArray: false }, (err, result) => {
      if (err) {
        return res.status(400).send({ error: err.message });
      }

      res.send(result);
    });
  });
});

app.listen(3000, () => {
  console.log('Server is listening on port 3000');
});